# Cohort stickiness analysis: compute DAU/MAU and retention curves

from datetime import date, timedelta
from collections import defaultdict
from dataclasses import dataclass

@dataclass
class UserSession:
    user_id: str
    session_date: date
    duration_minutes: float
    interactions: int

def build_cohort_table(sessions: list[UserSession]) -> dict[str, date]:
    """Map each user_id → their first active session date."""
    first: dict[str, date] = {}
    for s in sessions:
        if s.user_id not in first or s.session_date < first[s.user_id]:
            first[s.user_id] = s.session_date
    return first

def retention_at_days(
    cohort_table: dict[str, date],
    all_sessions: list[UserSession],
    day_offsets: list[int] = (7, 14, 30, 60, 90),
) -> dict[int, float]:
    """Compute % of cohort still active at each day offset."""
    session_dates: dict[str, set[date]] = defaultdict(set)
    for s in all_sessions:
        session_dates[s.user_id].add(s.session_date)

    result = {}
    for offset in day_offsets:
        window_start = lambda first: first + timedelta(days=offset - 3)
        window_end   = lambda first: first + timedelta(days=offset + 3)
        active = sum(
            1 for uid, first in cohort_table.items()
            if any(window_start(first) <= d <= window_end(first)
                   for d in session_dates.get(uid, set()))
        )
        result[offset] = round(active / len(cohort_table) * 100, 1) if cohort_table else 0
    return result

def dau_mau_ratio(sessions: list[UserSession], month: str) -> float:
    """
    month: "YYYY-MM"
    Returns DAU/MAU ratio for the given month.
    """
    month_sessions = [s for s in sessions if str(s.session_date)[:7] == month]
    if not month_sessions:
        return 0.0
    mau = len({s.user_id for s in month_sessions})
    # DAU = average daily unique users
    daily: dict[date, set] = defaultdict(set)
    for s in month_sessions:
        daily[s.session_date].add(s.user_id)
    avg_dau = sum(len(v) for v in daily.values()) / len(daily)
    return round(avg_dau / mau, 3)

# Session depth scoring: rate the quality of each user's engagement

def session_depth_score(
    sessions_30d: list[dict],  # each: {duration_min, interactions, features_used: list, output_exported: bool}
) -> dict:
    """
    Combines multiple depth signals into a 0-100 score.
    """
    if not sessions_30d:
        return {"score": 0, "details": {}}

    avg_duration = sum(s["duration_min"] for s in sessions_30d) / len(sessions_30d)
    avg_interactions = sum(s["interactions"] for s in sessions_30d) / len(sessions_30d)
    all_features = set()
    for s in sessions_30d:
        all_features.update(s.get("features_used", []))
    feature_breadth = len(all_features)
    export_rate = sum(1 for s in sessions_30d if s.get("output_exported")) / len(sessions_30d)

    # Component scores (each 0-25)
    dur_score = min(25, (avg_duration / 20) * 25)        # 20 min avg → full score
    int_score = min(25, (avg_interactions / 8) * 25)     # 8 interactions avg → full score
    feat_score = min(25, (feature_breadth / 5) * 25)     # 5 distinct features → full score
    exp_score = min(25, export_rate * 25)                # 100% export rate → full score

    total = round(dur_score + int_score + feat_score + exp_score, 1)
    return {
        "score": total,
        "details": {
            "avg_duration_min": round(avg_duration, 1),
            "avg_interactions": round(avg_interactions, 1),
            "feature_breadth": feature_breadth,
            "export_rate_pct": round(export_rate * 100, 1),
        },
    }

# Leading stickiness signal monitor for new cohorts

from datetime import date, timedelta
from dataclasses import dataclass
from typing import Optional

@dataclass
class CohortEarlySignal:
    user_id: str
    access_date: date
    onboarding_completed: Optional[date]
    champion_contact_date: Optional[date]
    week1_session_count: int
    week1_depth_score: float  # 0-100

    def onboarding_within_7d(self) -> bool:
        if not self.onboarding_completed:
            return False
        return (self.onboarding_completed - self.access_date).days <= 7

    def champion_within_14d(self) -> bool:
        if not self.champion_contact_date:
            return False
        return (self.champion_contact_date - self.access_date).days <= 14

    def leading_score(self) -> float:
        """0-100 leading indicator of D90 retention."""
        onboard = 33 if self.onboarding_within_7d() else 0
        champ = 33 if self.champion_within_14d() else 0
        depth = min(34, self.week1_depth_score * 0.34)
        return round(onboard + champ + depth, 1)

    def at_risk(self) -> bool:
        return self.leading_score() < 40
